using UnityEngine;

/// <summary>
/// Helpers partilhados pelas NpcActions.
/// </summary>
public static class NpcActionUtil
{
    /// <summary>
    /// Espera "seconds": em tempo real (WaitForSecondsRealtime) se o jogo
    /// estiver em pausa física (Time.timeScale == 0 — ver GamePauseUtil /
    /// Action_PauseGame, Etapa 8), ou em tempo de jogo (WaitForSeconds) caso
    /// contrário. Usado por todas as ações que esperam um tempo fixo, para que
    /// a sequência de ações do evento que pausou o jogo continue a correr em
    /// tempo real (e possa, por exemplo, retomar o jogo decorrido esse tempo).
    /// </summary>
    public static object Wait(float seconds)
    {
        return Time.timeScale <= 0f ? new WaitForSecondsRealtime(seconds) : new WaitForSeconds(seconds);
    }
}
